import { useEffect, useState } from "react";
import schoolsDepartments from "../../data/schoolsDepartments";
import { useAuth } from "../../context/AuthContext";

import DeanLayout from "../../layouts/DeanLayout";

import {

  getFacultySubmissions,

  downloadFacultyPDF

} from "../../api/deanApi";

function DeanFacultyReview() {

    const { user } = useAuth();
    const [selectedDepartment, setSelectedDepartment] =
  useState("");
  
  const [submissions, setSubmissions] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadFacultySubmissions();

  }, []);

  const loadFacultySubmissions =
    async () => {

      try {

        const res =
          await getFacultySubmissions();

        setSubmissions(

          res.data.submissions || []

        );

      }

      catch (err) {

        console.error(err);

      }

      finally {

        setLoading(false);

      }

    };

  // ==========================
  // PDF DOWNLOAD
  // ==========================

  const handleDownload =
    async (submission) => {

      try {

        const response =
          await downloadFacultyPDF(
            submission._id
          );

        const url =
          window.URL.createObjectURL(
            new Blob([response.data])
          );

        const link =
          document.createElement("a");

        link.href = url;

        link.download =
          `${submission.submittedByName}_${submission.quarter}.pdf`;

        document.body.appendChild(link);

        link.click();

        link.remove();

      }

      catch (error) {

        console.error(error);

      }

    };

  // ==========================
  // GROUP BY DEPARTMENT
  // ==========================

    // ==========================
// DEPARTMENTS OF DEAN SCHOOL
// ==========================

const departments =

  schoolsDepartments[user?.school] || [];

// ==========================
// FILTERED SUBMISSIONS
// ==========================

const filteredSubmissions =

  selectedDepartment

    ?

    submissions.filter(

      (submission) =>

        submission.department ===

        selectedDepartment

    )

    :

    [];

  return (

    <DeanLayout>

      <div
  style={{
    padding: "30px"
  }}
>

  <h1
    style={{
      marginBottom: "10px"
    }}
  >
    Faculty Reviews
  </h1>
 <div
  style={{
    marginBottom: "30px"
  }}
>

  <label
    style={{
      fontWeight: "600",
      display: "block",
      marginBottom: "10px"
    }}
  >

    Select Department

  </label>

  <select

    value={selectedDepartment}

    onChange={(e) =>

      setSelectedDepartment(

        e.target.value

      )

    }

    style={{

      width: "420px",

      padding: "12px",

      borderRadius: "8px",

      border: "1px solid #d1d5db"

    }}

  >

    <option value="">

      -- Select Department --

    </option>

    {

      departments.map(

        (department) => (

          <option

            key={department}

            value={department}

          >

            {department}

          </option>

        )

      )

    }

  </select>

</div>
  <p
    style={{
      color: "#6b7280",
      marginBottom: "30px"
    }}
  >
    Department-wise Faculty Submissions
    Approved by HOD
  </p>

{selectedDepartment === "" ? (

  <div
    style={{
      background: "#fff",
      padding: "30px",
      borderRadius: "12px",
      textAlign: "center",
      color: "#6b7280"
    }}
  >
    Please select a department.
  </div>

) : filteredSubmissions.length === 0 ? (

  <div
    style={{
      background: "#fff",
      padding: "30px",
      borderRadius: "12px",
      textAlign: "center",
      color: "#dc2626",
      fontWeight: "600"
    }}
  >
    NO FACULTY APPROVED BY HOD
  </div>

) : (

  <table
    style={{
      width: "100%",
      borderCollapse: "collapse",
      background: "#fff",
      borderRadius: "12px",
      overflow: "hidden",
      boxShadow: "0 2px 8px rgba(0,0,0,.08)"
    }}
  >

    <thead>

      <tr
        style={{
          background: "#2563eb",
          color: "#fff"
        }}
      >

        <th style={thStyle}>Faculty</th>

        <th style={thStyle}>Email</th>

        <th style={thStyle}>Department</th>

        <th style={thStyle}>Quarter</th>

        <th style={thStyle}>Answered</th>

        <th style={thStyle}>Submitted Date</th>

        <th style={thStyle}>Actions</th>

      </tr>

    </thead>

    <tbody>

      {filteredSubmissions.map((submission) => (

        <tr key={submission._id}>

          <td style={tdStyle}>
            {submission.submittedByName}
          </td>

          <td style={tdStyle}>
            {submission.submittedByEmail}
          </td>

          <td style={tdStyle}>
            {submission.department}
          </td>

          <td style={tdStyle}>
            {submission.quarter}
          </td>

          <td style={tdStyle}>
            {submission.answeredCount} / {submission.totalQuestions}
          </td>

          <td style={tdStyle}>
            {new Date(submission.createdAt).toLocaleDateString()}
          </td>

          <td style={tdStyle}>

            <button
              style={{
                padding: "8px 14px",
                background: "#2563eb",
                color: "#fff",
                border: "none",
                borderRadius: "6px",
                cursor: "pointer",
                marginRight: "10px"
              }}
            >
              👁 View
            </button>

            <button
              onClick={() =>
                handleDownload(submission)
              }
              style={{
                padding: "8px 14px",
                background: "#16a34a",
                color: "#fff",
                border: "none",
                borderRadius: "6px",
                cursor: "pointer"
              }}
            >
              📄 PDF
            </button>

          </td>

        </tr>

      ))}

    </tbody>

  </table>

)}

</div>
    </DeanLayout>

  );

}
const thStyle = {

  padding: "12px",

  textAlign: "left",

  background: "#dbeafe"

};

const tdStyle = {

  padding: "12px",

  borderBottom:
    "1px solid #e5e7eb"

};
export default DeanFacultyReview;
